function solve(nums, edges) {
    const n = nums.length;
    let count = 0;

    // 1. Build adjacency matrix/list for easier subgraph check
    const adj = Array(n).fill(0).map(() => Array(n).fill(false));
    for (const [u, v] of edges) {
        adj[u][v] = true;
        adj[v][u] = true;
    }

    // Iterate through all non-empty subsets (represented by bitmasks from 1 to 2^n - 1)
    const totalSubsets = 1 << n;

    for (let mask = 1; mask < totalSubsets; mask++) {
        // 2. Check condition 2: Sum of values must be even
        let sum = 0;
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                sum += nums[i];
            }
        }

        if (sum % 2 !== 0) {
            continue; // Skip if sum is odd
        }

        // 3. Check condition 1: Induced subgraph must be connected

        // Identify the nodes in the subset s
        const subsetNodes = [];
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                subsetNodes.push(i);
            }
        }

        if (subsetNodes.length === 0) continue; // Should not happen based on mask starting at 1

        // Check connectivity using BFS/DFS starting from the first node in the subset
        const startNode = subsetNodes[0];
        const visited = new Set();
        const queue = [startNode];
        visited.add(startNode);
        let visitedCount = 0;

        while (queue.length > 0) {
            const u = queue.shift();
            visitedCount++;

            // Check neighbors 'v' of 'u'
            for (let v = 0; v < n; v++) {
                // Check if v is in the subset (mask) AND is adjacent to u (in induced subgraph) AND not yet visited
                if (((mask >> v) & 1) && adj[u][v] && !visited.has(v)) {
                    visited.add(v);
                    queue.push(v);
                }
            }
        }

        // If the number of visited nodes equals the total number of nodes in the subset, it is connected.
        if (visitedCount === subsetNodes.length) {
            count++;
        }
    }

    return count;
}

